// =============================================================================
// 统一存储架构：historyViewSettings
// 将所有视图设置存储在 chrome.storage.local，替代分散的 localStorage
// 这样 background.js (Service Worker) 也能访问这些设置，实现 WYSIWYG 导出
// =============================================================================
let historyDetailMode = 'collection'; // 默认值，将在初始化时从 chrome.storage.local 加载
let historyViewSettings = null;   // 缓存视图设置对象
let historyViewSettingsSaveTimeout = null; // 防抖保存定时器

// 旧的 localStorage 键前缀（用于迁移）
const HISTORY_DETAIL_MODE_PREFIX = 'historyDetailMode:';
const HISTORY_DETAIL_EXPANDED_PREFIX = 'historyDetailExpanded:';

function normalizeHistoryDetailMode(mode, fallback = 'simple') {
    const value = String(mode || '').toLowerCase();
    if (value === 'simple') return 'simple';
    if (value === 'detailed') return 'detailed';
    if (value === 'collection') return 'collection';
    const normalizedFallback = String(fallback || '').toLowerCase();
    if (normalizedFallback === 'detailed') return 'detailed';
    if (normalizedFallback === 'collection') return 'collection';
    return 'simple';
}

function getHistoryDetailModeLabel(mode, isZh = currentLang === 'zh_CN') {
    const normalized = normalizeHistoryDetailMode(mode);
    if (normalized === 'detailed') return isZh ? '详细' : 'Detailed';
    if (normalized === 'collection') return isZh ? '集合' : 'Collection';
    return isZh ? '简略' : 'Simple';
}

/**
 * 从 chrome.storage.local 加载视图设置
 * @returns {Promise<Object>} 视图设置对象
 */
async function loadHistoryViewSettings() {
    return new Promise(resolve => {
        const browserAPI = (typeof chrome !== 'undefined' && chrome.storage) ? chrome : (typeof browser !== 'undefined' ? browser : null);
        if (!browserAPI || !browserAPI.storage) {
            
            historyViewSettings = { defaultMode: 'collection', recordModes: {}, recordExpandedStates: {} };
            historyDetailMode = 'collection';
            resolve(historyViewSettings);
            return;
        }
        browserAPI.storage.local.get(['historyViewSettings'], result => {
            const rawSettings = result.historyViewSettings || {
                defaultMode: 'collection',
                recordModes: {},
                recordExpandedStates: {}
            };
            const normalizedRecordModes = {};
            Object.entries(rawSettings.recordModes || {}).forEach(([recordTime, mode]) => {
                normalizedRecordModes[String(recordTime)] = normalizeHistoryDetailMode(mode);
            });
            historyViewSettings = {
                defaultMode: normalizeHistoryDetailMode(rawSettings.defaultMode, 'collection'),
                recordModes: normalizedRecordModes,
                recordExpandedStates: (rawSettings && typeof rawSettings.recordExpandedStates === 'object' && rawSettings.recordExpandedStates)
                    ? rawSettings.recordExpandedStates
                    : {}
            };
            historyDetailMode = historyViewSettings.defaultMode || 'collection';
            
            resolve(historyViewSettings);
        });
    });
}

/**
 * 保存视图设置到 chrome.storage.local（带防抖 300ms）
 * @returns {Promise<void>}
 */
async function saveHistoryViewSettings() {
    if (historyViewSettingsSaveTimeout) {
        clearTimeout(historyViewSettingsSaveTimeout);
    }
    return new Promise(resolve => {
        historyViewSettingsSaveTimeout = setTimeout(async () => {
            const browserAPI = (typeof chrome !== 'undefined' && chrome.storage) ? chrome : (typeof browser !== 'undefined' ? browser : null);
            if (!browserAPI || !browserAPI.storage || !historyViewSettings) {
                resolve();
                return;
            }
            await new Promise(r => {
                browserAPI.storage.local.set({ historyViewSettings }, r);
            });
            
            resolve();
        }, 300);
    });
}

/**
 * 将 localStorage 中的历史视图设置迁移到 chrome.storage.local
 * 只在首次加载时执行一次
 */
async function migrateHistoryViewSettingsFromLocalStorage() {
    const browserAPI = (typeof chrome !== 'undefined' && chrome.storage) ? chrome : (typeof browser !== 'undefined' ? browser : null);
    if (!browserAPI || !browserAPI.storage) return;

    // 检查是否已迁移
    const result = await new Promise(resolve => {
        browserAPI.storage.local.get(['historyViewSettingsMigrated'], resolve);
    });

    if (result.historyViewSettingsMigrated) {
        
        return;
    }

    

    const newSettings = {
        defaultMode: 'collection',
        recordModes: {},
        recordExpandedStates: {}
    };

    try {
        // 迁移全局默认模式
        const defaultMode = localStorage.getItem('historyDetailMode');
        if (defaultMode === 'simple' || defaultMode === 'detailed' || defaultMode === 'collection') {
            newSettings.defaultMode = normalizeHistoryDetailMode(defaultMode);
        }

        // 遍历 localStorage，找出所有历史相关的 key
        for (let i = 0; i < localStorage.length; i++) {
            const key = localStorage.key(i);
            if (!key) continue;

            // 迁移每条记录的视图模式
            if (key.startsWith(HISTORY_DETAIL_MODE_PREFIX)) {
                const recordTime = key.replace(HISTORY_DETAIL_MODE_PREFIX, '');
                const mode = localStorage.getItem(key);
                if (mode === 'simple' || mode === 'detailed' || mode === 'collection') {
                    newSettings.recordModes[recordTime] = normalizeHistoryDetailMode(mode);
                }
            }

            // 迁移每条记录的展开状态
            if (key.startsWith(HISTORY_DETAIL_EXPANDED_PREFIX)) {
                const recordTime = key.replace(HISTORY_DETAIL_EXPANDED_PREFIX, '');
                try {
                    const expandedIds = JSON.parse(localStorage.getItem(key));
                    if (Array.isArray(expandedIds)) {
                        newSettings.recordExpandedStates[recordTime] = expandedIds;
                    }
                } catch (e) { }
            }
        }

        // 保存到 chrome.storage.local
        await new Promise(resolve => {
            browserAPI.storage.local.set({
                historyViewSettings: newSettings,
                historyViewSettingsMigrated: true
            }, resolve);
        });

        // 更新全局变量
        historyViewSettings = newSettings;
        historyDetailMode = normalizeHistoryDetailMode(newSettings.defaultMode);

        
        

    } catch (error) {
        console.error('[迁移] 迁移失败:', error);
    }
}
