function formatTime(timestamp) {
    const date = new Date(timestamp);
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    const seconds = String(date.getSeconds()).padStart(2, '0');

    return `${year}/${month}/${day} ${hours}:${minutes}:${seconds}`;
}

// 用于导出文件名的本地时间格式化（避免 toISOString 的 UTC 时区问题）
function formatTimeForFilename(timestamp) {
    const date = timestamp ? new Date(timestamp) : new Date();
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    const hours = String(date.getHours()).padStart(2, '0');
    const minutes = String(date.getMinutes()).padStart(2, '0');
    const seconds = String(date.getSeconds()).padStart(2, '0');
    return `${year}-${month}-${day}_${hours}-${minutes}-${seconds}`;
}

function sanitizeFilenameSegment(text) {
    return String(text || '')
        .replace(/[\\/:*?"<>|]/g, '_')
        .replace(/\s+/g, '_')
        .replace(/_+/g, '_')
        .replace(/^_+|_+$/g, '');
}

function buildSequenceMapFromHistory(historyRecords) {
    const records = Array.isArray(historyRecords) ? historyRecords.slice() : [];
    records.sort((a, b) => getHistoryRecordTimeMs(a) - getHistoryRecordTimeMs(b));
    const map = new Map();
    const used = new Set();
    for (const r of records) {
        const seq = Number(r?.seqNumber);
        if (Number.isFinite(seq) && seq > 0) used.add(seq);
    }
    let next = 1;
    for (const r of records) {
        let seq = Number(r?.seqNumber);
        if (!(Number.isFinite(seq) && seq > 0)) {
            while (used.has(next)) next++;
            seq = next;
            used.add(seq);
            next++;
        }
        map.set(String(r.time), seq);
    }
    return map;
}

function formatSelectedSequenceRanges(seqNumbers, lang) {
    const delim = lang === 'zh_CN' ? '、' : ',';
    const nums = Array.from(new Set((seqNumbers || []).filter(n => Number.isFinite(n) && n > 0)))
        .sort((a, b) => a - b);
    if (nums.length === 0) return '';

    const parts = [];
    let start = nums[0];
    let end = nums[0];
    for (let i = 1; i < nums.length; i++) {
        const n = nums[i];
        if (n === end + 1) {
            end = n;
            continue;
        }
        parts.push(start === end ? String(start) : `${start}-${end}`);
        start = n;
        end = n;
    }
    parts.push(start === end ? String(start) : `${start}-${end}`);
    return parts.join(delim);
}

function generateBookmarkExportHTMLFromTree(treeRoot) {
    const escapeAttr = (s) => String(s ?? '').replace(/&/g, '&amp;').replace(/"/g, '&quot;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    const escapeText = (s) => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

    let html = '<!DOCTYPE NETSCAPE-Bookmark-file-1>\n';
    html += '<META HTTP-EQUIV="Content-Type" CONTENT="text/html; charset=UTF-8">\n';
    html += '<TITLE>Bookmarks</TITLE>\n';
    html += '<H1>Bookmarks</H1>\n';
    html += '<DL><p>\n';

    const generateNodeHTML = (node, indentLevel) => {
        const indent = '    '.repeat(indentLevel);
        const title = escapeText(node?.title || '');
        const url = node?.url ? String(node.url) : '';
        const isFolder = !url && node && Array.isArray(node.children);

        if (isFolder) {
            let result = `${indent}<DT><H3>${title}</H3>\n`;
            result += `${indent}<DL><p>\n`;
            node.children.forEach(child => {
                result += generateNodeHTML(child, indentLevel + 1);
            });
            result += `${indent}</DL><p>\n`;
            return result;
        }

        if (url) {
            return `${indent}<DT><A HREF="${escapeAttr(url)}">${title}</A>\n`;
        }

        // fallback: treat as folder-ish if children exists, otherwise skip
        if (node && Array.isArray(node.children)) {
            let result = `${indent}<DT><H3>${title}</H3>\n`;
            result += `${indent}<DL><p>\n`;
            node.children.forEach(child => {
                result += generateNodeHTML(child, indentLevel + 1);
            });
            result += `${indent}</DL><p>\n`;
            return result;
        }

        return '';
    };

    const nodes = Array.isArray(treeRoot) ? treeRoot : [treeRoot];
    nodes.forEach(root => {
        if (!root) return;
        if (root.title) {
            html += generateNodeHTML({ title: root.title, children: root.children || [] }, 1);
            return;
        }
        if (Array.isArray(root.children)) {
            root.children.forEach(child => {
                html += generateNodeHTML(child, 1);
            });
        }
    });

    html += '</DL><p>\n';
    return html;
}

function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

function showLoading() {
    document.querySelectorAll('.view.active .history-commits, .view.active .bookmark-tree').forEach(el => {
        el.innerHTML = `<div class="loading">${i18n.loading[currentLang]}</div>`;
    });
}

function showError(message) {
    const container = document.querySelector('.view.active > div:last-child');
    if (container) {
        container.innerHTML = `
            <div class="empty-state">
                <div class="empty-state-icon"><i class="fas fa-exclamation-triangle"></i></div>
                <div class="empty-state-title">${escapeHtml(message)}</div>
            </div>
        `;
    }
}

function showToast(message, type = 'info', duration = 2000) {
    showHistoryPageToast(message, { type, duration });
}


function formatRestoreRecoveryPhaseLabel(phase, lang = currentLang) {
    const normalized = String(phase || '').toLowerCase();
    const isEn = lang === 'en';
    if (normalized === 'intent_preparing_target') return isEn ? 'Preparing Target Snapshot' : '正在准备目标快照';
    if (normalized === 'snapshot_ready') return isEn ? 'Snapshot Ready' : '快照已就绪';
    if (normalized === 'destructive_started') return isEn ? 'Destructive Phase' : '破坏性阶段';
    if (normalized === 'apply_started') return isEn ? 'Applying Changes' : '正在应用变更';
    if (normalized === 'finalizing') return isEn ? 'Finalizing' : '正在收尾';
    if (normalized === 'continue_failed') return isEn ? 'Continue Failed' : '继续失败';
    if (normalized === 'rollback_failed') return isEn ? 'Rollback Failed' : '回滚失败';
    if (normalized === 'locked_incident') return isEn ? 'Locked Incident' : '故障锁定';
    if (normalized === 'completed') return isEn ? 'Completed' : '已完成';
    return normalized || (isEn ? 'Unknown' : '未知');
}

function formatRestoreRecoveryTimeLabel(value, lang = currentLang) {
    const date = new Date(value || Date.now());
    if (!Number.isFinite(date.getTime())) return String(value || '');
    try {
        return date.toLocaleString(lang === 'en' ? 'en-US' : 'zh-CN');
    } catch (_) {
        return date.toISOString();
    }
}

function isRestoreRecoveryLockedResponse(response) {
    return !!(response && response.errorCode === 'restore_recovery_locked');
}

function promptRestoreRecoveryTransactionFromHistory() {
    Promise.resolve().then(() => maybePromptRestoreRecoveryTransactionInHistory().catch(() => { }));
}

let restoreRecoveryBlockingOverlayState = null;

function closeRestoreRecoveryBlockingOverlayInHistory() {
    const state = restoreRecoveryBlockingOverlayState;
    restoreRecoveryBlockingOverlayState = null;
    if (!state) return;

    if (typeof state.unlockConfirmCleanup === 'function') {
        state.unlockConfirmCleanup();
    }
    if (state.timer) {
        window.clearInterval(state.timer);
    }
    if (state.actionHintTimer) {
        window.clearInterval(state.actionHintTimer);
    }
    if (state.keydownHandler) {
        document.removeEventListener('keydown', state.keydownHandler, true);
    }
    if (state.focusHandler) {
        document.removeEventListener('focusin', state.focusHandler, true);
    }
    if (state.overlay?.parentNode) {
        state.overlay.parentNode.removeChild(state.overlay);
    }
}

function formatRestoreRecoveryUiSourceLabel(value, lang = currentLang) {
    const normalized = String(value || '').toLowerCase();
    const isEn = lang === 'en';
    if (normalized === 'history') return isEn ? 'History Page' : 'HTML 历史页';
    if (normalized === 'background') return isEn ? 'Background' : '后台';
    return isEn ? 'Main UI' : '主 UI';
}

